import React, { useState, useEffect } from 'react';
import './CommandeForm.css';

const CommandeForm = ({ selectedCommande, onSuccess, onCancel }) => {
  const [formData, setFormData] = useState({
    codeCli: '',
    codeArt: '',
    dateCom: '',
    QteCom: ''
  });

  const [message, setMessage] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    if (selectedCommande) {
      const { idCOM, ...rest } = selectedCommande;
      setFormData(rest);
    } else {
      resetForm();
    }
  }, [selectedCommande]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const resetForm = () => {
    setFormData({
      codeCli: '',
      codeArt: '',
      dateCom: '',
      QteCom: ''
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const method = selectedCommande ? 'PUT' : 'POST';
    const url = selectedCommande
      ? `http://localhost:3001/commandes/${selectedCommande.idCOM}`
      : 'http://localhost:3001/commandes';

    try {
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      setMessage(selectedCommande ? 'Commande modifiée avec succès.' : 'Commande ajoutée avec succès.');
      setError('');
      resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      setError(err.message);
      setMessage('');
    }
  };

  const handleDelete = async () => {
    if (!selectedCommande) return;

    const confirmDelete = window.confirm('Supprimer cette commande ?');
    if (!confirmDelete) return;

    try {
      const res = await fetch(`http://localhost:3001/commandes/${selectedCommande.idCOM}`, {
        method: 'DELETE'
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      setMessage('Commande supprimée avec succès.');
      setError('');
      resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      setError(err.message);
      setMessage('');
    }
  };

  const handleVoirFacture = (commande) => {
    alert(`
📄 Facture de la commande #${commande.idCOM}
Client : ${commande.codeCli}
Article : ${commande.codeArt}
Date : ${commande.dateCom}
Quantité : ${commande.QteCom}
    `);
  };

  return (
    <form onSubmit={handleSubmit} className="commande-form">
      {selectedCommande && (
        <div>
          <label>ID Commande :</label>
          <input type="text" value={selectedCommande.idCOM} readOnly />
        </div>
      )}

      <input
        name="codeCli"
        placeholder="Code Client"
        value={formData.codeCli}
        onChange={handleChange}
        required
      />
      <input
        name="codeArt"
        placeholder="Code Article"
        value={formData.codeArt}
        onChange={handleChange}
        required
      />
      <input
        type="date"
        name="dateCom"
        placeholder="Date de commande"
        value={formData.dateCom}
        onChange={handleChange}
        required
      />
      <input
        type="number"
        name="QteCom"
        placeholder="Quantité"
        value={formData.QteCom}
        onChange={handleChange}
        required
      />

      <button type="submit">
        {selectedCommande ? 'Modifier' : 'Ajouter'}
      </button>

      {selectedCommande && (
        <>
          <button type="button" onClick={handleDelete}>Supprimer</button>
          <button type="button" onClick={() => handleVoirFacture(selectedCommande)}>Voir facture</button>
          <button type="button" onClick={onCancel}>Annuler</button>
        </>
      )}

      {message && <div className="success">{message}</div>}
      {error && <div className="error">{error}</div>}
    </form>
  );
};

export default CommandeForm;
